  svg.setAttribute(
    "viewBox",
    `${box.x} ${box.y - KATANA_DRAWIO_EXPORT_TOP_PADDING} ${box.width} ${box.height + KATANA_DRAWIO_EXPORT_TOP_PADDING}`,
  );
